#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node* next;
} Node;

Node* newNode(int val) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->data = val;
    n->next = NULL;
    return n;
}

Node* reverseMSizeGroups(Node* head, int M) {
    Node *prevGroupTail = NULL, *newHead = NULL;
    Node *curr = head;
    while (curr) {
        Node *groupHead = curr;
        Node *prev = NULL;
        int cnt = 0;
        // reverse exactly M nodes
        while (curr && cnt < M) {
            Node* nxt = curr->next;
            curr->next = prev;
            prev = curr;
            curr = nxt;
            cnt++;
        }
        // prev is the new head of this group, groupHead is its tail
        if (!newHead) newHead = prev;
        if (prevGroupTail) prevGroupTail->next = prev;
        prevGroupTail = groupHead;
    }
    return newHead;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        Node *head = NULL, *tail = NULL;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            Node* nd = newNode(x);
            if (!head) head = nd;
            else tail->next = nd;
            tail = nd;
        }
        head = reverseMSizeGroups(head, M);
        // print result
        Node* p = head;
        while (p) {
            printf("%d", p->data);
            if (p->next) printf(" ");
            p = p->next;
        }
        printf("\n");
        // free list
        while (head) {
            Node* tmp = head;
            head = head->next;
            free(tmp);
        }
    }
    return 0;
}

