code.Java:
import java.io.*;
import java.util.*;

class Main {
    static class Node {
        int data;
        Node next;
        Node(int d) { data = d; }
    }

    static Node reverseMSizeGroups(Node head, int M) {
        Node prevGroupTail = null, newHead = null;
        Node curr = head;
        while (curr != null) {
            Node groupHead = curr;
            Node prev = null;
            int cnt = 0;
            while (curr != null && cnt < M) {
                Node nxt = curr.next;
                curr.next = prev;
                prev = curr;
                curr = nxt;
                cnt++;
            }
            if (newHead == null) newHead = prev;
            if (prevGroupTail != null) prevGroupTail.next = prev;
            prevGroupTail = groupHead;
        }
        return newHead;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            Node head = null, tail = null;
            for (int i = 0; i < N; ++i) {
                int val = Integer.parseInt(st.nextToken());
                Node nd = new Node(val);
                if (head == null) head = nd; else tail.next = nd;
                tail = nd;
            }
            head = reverseMSizeGroups(head, M);
            for (Node p = head; p != null; p = p.next) {
                out.append(p.data);
                if (p.next != null) out.append(' ');
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

